// Time:  O(n)
// Space: O(1)

class Solution {
public:
    string thousandSeparator(int n) {
        string result;
        const auto& s = to_string(n);
        for (int i = 0; i < s.length(); ++i) {
            if (i > 0 && (s.length() - i) % 3 == 0) {
                result += ".";
            }
            result += s[i];
        }
        return result;
    }
};

# Time:  O(n)
# Space: O(1)

class Solution(object):
    def thousandSeparator(self, n):
        """
        :type n: int
        :rtype: str
        """
        result = []
        s = str(n)
        for i, c in enumerate(str(n)):
            if i and (len(s)-i)%3 == 0:
                result.append(".")
            result.append(c)
        return "".join(result)
